object ChemistryConceptExperiences {
 private fun v(s:String,m:String,u:String,t:String,r:String)=FormulaVariableLink(s,m,u,t,r)
 private fun p(id:String,loc:String,input:String,action:String,output:String,why:String,error:String)=ProcessStep(id,loc,listOf(input),action,listOf(output),why,error)
 private fun build(id:String,c:AuthoredExperienceCopy)=ConceptExperienceAuthoring.build(ChemistryInteractiveReference.definitions.single{it.activityId==id},c)
 val atom=build("chemistry-atom-builder",AuthoredExperienceCopy("Atomic structure · Atoms, isotopes and ions","A nucleus-and-shell builder connects subatomic counts to element identity, isotope mass, charge, and shell occupancy.",listOf("whole-number counting","positive and negative charge"),"Proton number Z fixes the element. Neutrons change mass number without changing element identity. Electrons change net charge; the shell drawing is a school-level occupancy model.","Electron shells are useful representations, but electrons are not tiny planets following fixed classical tracks.","Six protons and eight neutrons form carbon-14; six electrons make it neutral, while five make charge +1e.","If one neutron is added, which labels change?","Mass number changes; atomic number, element identity, and charge remain fixed.","Changing neutrons creates a different element.","Add neutrons while keeping protons fixed and compare the element symbol and mass number.","The isotope changes, not the element, because nuclear charge is unchanged.","Build a neutral atom with Z=8 and A=16.","8 protons, 8 neutrons, 8 electrons","Z fixes eight protons; A−Z gives eight neutrons; neutrality requires equal electrons.","Protons identify the element, neutrons identify its isotope, and electron imbalance identifies its ion.","nucleus",listOf(v("Z","atomic number","","protons","equals proton count"),v("A","mass number","","nucleus","protons plus neutrons"),v("q/e","charge number","elementary charges","shells","protons minus electrons")),comparisonLabels="isotope change" to "ion change"))
 val periodic=build("chemistry-periodic-trends",AuthoredExperienceCopy("Periodicity · First 18 elements","A periodic-grid comparison connects period and group position to qualitative atomic-radius and electronegativity trends.",listOf("atomic number","electron shells"),"Across a period, nuclear charge increases while electrons enter the same main shell, so effective attraction generally strengthens and radius decreases. Down a group, a new shell usually increases radius.","Trend arrows express broad patterns; they are not substitutes for measured data and exceptions.","Across Period 3, sodium is qualitatively larger and less electronegative than chlorine.","Compare lithium and sodium: which has the larger radius trend?","Sodium is lower in Group 1 and has an additional occupied shell, so its radius trend is larger.","Every property changes perfectly smoothly across the table.","Compare several neighbours and read the model limitation before generalising.","Periodic trends are useful generalisations with property-specific exceptions.","Between Na and Cl, which is expected to attract bonding electrons more strongly?","Cl","Electronegativity generally increases across Period 3.","Position organises recurring electronic structure and explains broad, qualified trends.","table",listOf(v("Z","atomic number","","atomicNumber","selects element"),v("period","occupied-shell level","","table","downward trend"),v("group","valence-pattern column","","table","recurrence"),v("χ","electronegativity trend","relative units","en","generally rises across")),comparisonLabels="across a period" to "down a group"))
 val bonding=build("chemistry-bonding",AuthoredExperienceCopy("Bonding · Electron sharing and polarity","A two-atom bond model connects shared-pair count and electronegativity difference to bond polarity and cautious classification.",listOf("valence electrons","absolute difference"),"Covalent bonding shares electron density. Unequal electronegativity shifts that density toward one atom. Large differences indicate strong ionic character, but bond character is continuous rather than a perfect threshold.","Bond polarity is not the same as whole-molecule polarity; geometry determines whether bond dipoles cancel.","A bond between χ=2.1 and χ=3.5 has Δχ=1.4 and is polar covalent in this teaching convention.","If both electronegativities increase equally, what happens to Δχ?","The difference and polarity proxy stay unchanged, even though both absolute values changed.","Every compound can be labelled purely ionic or purely covalent from one cutoff.","Move Δχ gradually across a teaching threshold and observe that the numerical polarity changes continuously.","Classification words are approximations applied to continuous electron-density behaviour.","Which way does the dipole arrow point for χ₁=2.0 and χ₂=3.0?","Toward atom 2","Electron density shifts toward the more electronegative atom.","Use Δχ as evidence, state the model convention, and separate bond polarity from molecular polarity.","bond",listOf(v("χ₁","electronegativity of atom 1","Pauling units","atom1","input"),v("χ₂","electronegativity of atom 2","Pauling units","atom2","input"),v("Δχ","electronegativity difference","Pauling units","bond","polarity proxy")),comparisonLabels="mostly non-polar" to "polar/strong ionic character"))
 val gas=build("chemistry-gas-laws",AuthoredExperienceCopy("States and gas laws · Ideal gas model","A piston, representative particles, pressure gauge, and P–V point connect the macroscopic gas state to a particle explanation and PV=nRT.",listOf("kelvin temperature","moles","volume"),"Pressure results from particle-wall momentum transfers. Compressing the ideal gas at fixed n and T raises collision frequency per area; heating raises the representative speed proxy and pressure.","Temperature must be absolute kelvin in the ideal-gas equation.","One mole at 300 K in about 24.6 L gives approximately 1 atm with R=0.082057 L atm mol⁻¹ K⁻¹.","At fixed n and V, what happens to pressure when kelvin temperature doubles?","Pressure doubles in the ideal model, and the speed proxy increases by √2.","Gas particles themselves expand when the gas volume increases.","Increase container volume and compare particle count, spacing depiction, and pressure.","The container volume and average spacing change; individual particle size is not modeled as expanding.","Find the pressure of 1 mol at 300 K in 10 L.","About 2.46 atm","P=nRT/V=1×0.082057×300/10.","The ideal-gas equation connects state variables; the particle picture explains the direction of change.","piston",listOf(v("P","pressure","atm","gauge","output"),v("V","volume","L","piston","inverse at fixed n,T"),v("n","amount","mol","particles","direct"),v("T","absolute temperature","K","temperature","direct")),comparisonLabels="expanded state" to "compressed state"))
 val titration=build("chemistry-titration",AuthoredExperienceCopy("Acids and bases · Strong acid–base titration","A burette, flask, mole balance, and curve connect measured volume to excess species, pH, and equivalence.",listOf("molarity","moles","logarithms"),"For a 1:1 strong acid–base reaction, compare moles H⁺ initially present with moles OH⁻ added. Before equivalence acid remains; after equivalence base remains; at ideal 25 °C equivalence has pH 7.","The indicator endpoint is an observed colour transition near equivalence, not automatically the exact stoichiometric point.","25.0 mL of 0.100 mol/L acid requires 25.0 mL of 0.100 mol/L base for equivalence.","If base concentration doubles, what happens to equivalence volume?","It halves because the same required moles are delivered in half the volume.","Neutralisation always means the final pH is exactly 7.","Move beyond equivalence and inspect the excess-base mole balance and pH.","Only the stated strong acid–strong base equivalence is neutral at 25 °C; excess reagent and weak systems differ.","What volume of 0.20 mol/L base neutralises 25.0 mL of 0.10 mol/L monoprotic acid?","12.5 mL","MₐVₐ=MᵦVᵦ for the stated 1:1 reaction.","Equivalence is a mole condition; pH and indicator endpoint must be interpreted with the chemical model.","curve",listOf(v("Mₐ","acid concentration","mol/L","flask","direct moles"),v("Vₐ","acid volume","mL","flask","direct moles"),v("Mᵦ","base concentration","mol/L","burette","inverse effect on equivalence volume"),v("Vᵦ","base delivered","mL","burette","titration coordinate"),v("pH","acidity scale","","curve","logarithmic output")),listOf(p("titrate","flask","known acid and measured base addition","compare reacting moles and remove the limiting species","excess H+ or OH− and pH","Stoichiometry determines excess before the logarithmic pH calculation.","Do not identify equivalence from volume alone when concentrations differ."))))
 val all=listOf(atom,periodic,bonding,gas,titration)
}
